112→export async function listWorkspaceOpenObservations(input: {
113→  surreal: Surreal;
114→  workspaceRecord: RecordId<"workspace", string>;
115→  limit: number;
116→}): Promise<ObservationSummary[]> {
117→  const [rows] = await input.surreal
118→    .query<[
119→      Array<{
120→        id: ObservationRecord;
121→        text: string;
122→        severity: ObservationSeverity;
123→        status: ObservationStatus;
124→        category?: EntityCategory;
125→        source_agent: string;
126→        created_at: string | Date;
127→      }>,
128→    ]>(
129→      [
130→        "SELECT id, text, severity, status, category, source_agent, created_at",
131→        "FROM observation",
132→        "WHERE workspace = $workspace",
133→        "AND status IN ['open', 'acknowledged']",
134→        "ORDER BY created_at DESC",
135→        "LIMIT $limit;",
136→      ].join(" "),
137→      {
138→        workspace: input.workspaceRecord,
139→        limit: input.limit,
140→      },
141→    )
142→    .collect<[
143→      Array<{
144→        id: ObservationRecord;
145→        text: string;
146→        severity: ObservationSeverity;
147→        status: ObservationStatus;
148→        category?: EntityCategory;
149→        source_agent: string;
150→        created_at: string | Date;
151→      }>,
152→    ]>();
153→
154→  return rows
155→    .slice()
156→    .sort((a, b) => {
157→      const severityDelta = SEVERITY_PRIORITY[a.severity] - SEVERITY_PRIORITY[b.severity];
158→      if (severityDelta !== 0) {
159→        return severityDelta;
160→      }
161→
162→      return new Date(b.created_at).getTime() - new Date(a.created_at).getTime();
163→    })
164→    .map((row) => ({
165→      id: row.id.id as string,
166→      text: row.text,
167→      severity: row.severity,
168→      status: row.status,
169→      ...(row.category ? { category: row.category } : {}),
170→      sourceAgent: row.source_agent,
171→      createdAt: row.created_at instanceof Date ? row.created_at.toISOString() : new Date(row.created_at).toISOString(),
172→    }));
173→}
