229→  it("superseding a learning marks the old one as superseded and creates an edge", async () => {
230→    const { surreal } = getRuntime();
231→
232→    // Given a workspace with an active learning about database choice
233→    const { workspaceId } = await createTestWorkspace(surreal, "supersede");
234→    const { learningId: oldLearningId } = await createTestLearning(surreal, workspaceId, {
235→      text: "Use MySQL for all persistent storage.",
236→      learning_type: "precedent",
237→      status: "active",
238→    });
239→
240→    // When the human creates a new learning that supersedes it
241→    const { learningId: newLearningId } = await createTestLearning(surreal, workspaceId, {
242→      text: "Use SurrealDB for all persistent storage (supersedes MySQL decision).",
243→      learning_type: "precedent",
244→      status: "active",
245→    });
246→
247→    // And the supersession is recorded
248→    const oldLearningRecord = new RecordId("learning", oldLearningId);
249→    const newLearningRecord = new RecordId("learning", newLearningId);
250→
251→    await surreal.query(
252→      `UPDATE $old SET status = "superseded", updated_at = time::now();`,
253→      { old: oldLearningRecord },
254→    );
255→
256→    await surreal.query(
257→      `RELATE $new->supersedes->$old SET superseded_at = time::now(), reason = "Migrated from MySQL to SurrealDB";`,
258→      { new: newLearningRecord, old: oldLearningRecord },
259→    );
260→
261→    // Then the old learning is superseded
262→    const oldLearning = await getLearningById(surreal, oldLearningId);
263→    expect(oldLearning!.status).toBe("superseded");
264→
265→    // And the supersession edge exists
266→    const hasEdge = await getSupersessionEdge(surreal, newLearningId, oldLearningId);
267→    expect(hasEdge).toBe(true);
268→
269→    // And only the new learning appears in active list
270→    const activeLearnings = await listActiveLearnings(surreal, workspaceId);
271→    expect(activeLearnings.length).toBe(1);
272→    expect(activeLearnings[0].text).toContain("SurrealDB");
273→  }, 120_000);
