 69→export async function acceptSuggestion(input: {
 70→  surreal: Surreal;
 71→  workspaceRecord: RecordId<"workspace", string>;
 72→  suggestionRecord: SuggestionRecord;
 73→  now: Date;
 74→}): Promise<void> {
 75→  const row = await input.surreal.select<{ workspace: RecordId<"workspace", string> }>(input.suggestionRecord);
 76→  if (!row) {
 77→    throw new Error(`suggestion not found: ${input.suggestionRecord.id as string}`);
 78→  }
 79→
 80→  if ((row.workspace.id as string) !== (input.workspaceRecord.id as string)) {
 81→    throw new Error("suggestion is outside the current workspace scope");
 82→  }
 83→
 84→  await input.surreal.update(input.suggestionRecord).merge({
 85→    status: "accepted" satisfies SuggestionStatus,
 86→    accepted_at: input.now,
 87→    updated_at: input.now,
 88→  });
 89→}
