212→    throw new Error(`suggestion not found: ${input.suggestionRecord.id as string}`);
213→  }
214→  if ((row.workspace.id as string) !== (input.workspaceRecord.id as string)) {
215→    throw new Error("suggestion is outside the current workspace scope");
216→  }
217→  if (!["pending", "accepted", "deferred"].includes(row.status)) {
218→    throw new Error(`suggestion cannot be converted from status '${row.status}'`);
219→  }
